import { Box, Button} from "@mui/material";

const HeaderMenuNav = () => {   

    return (
        <Box sx={{ flexGrow: 1, display: { xs: 'none', md: 'flex' } }}>
            <Button key={"seasons"}
                href="/Seasons"
                sx={{ my: 2, color: 'white', display: 'block' }}
            >
            Seasons
            </Button>
            <Button key={"players"}
                href="/Players"
                sx={{ my: 2, color: 'white', display: 'block' }}
            >
            Players
            </Button>            
    </Box>
    )

}

export default HeaderMenuNav;
